// src/worker.js
import { CHAT_PASSWORD, DEFAULT_MODEL, MODELS, PROMPT_1, PROMPT_2,  PROMPT_3} from "./config.js";

// Donate image served as /donate.png
const DONATE_PNG_BASE64 = "";

// Static assets embedded as strings (no build step)
const INDEX_HTML = "<!DOCTYPE html>\n<html>\n<head>\n<meta charset=\"UTF-8\" />\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0, viewport-fit=cover\" />\n<title>DeepSeek Chat</title>\n<link rel=\"stylesheet\" href=\"/styles.css\" />\n</head>\n<body>\n<div id=\"app\">\n  <div id=\"topbar\">\n    <div class=\"topbar-inner\">\n      <button class=\"iconbtn\" id=\"donateBtn\" title=\"\u6253\u8d4f / Donate\">\ud83d\udc9a</button>\n\n      <div class=\"pill\">\n        <label>Model</label>\n        <select id=\"modelSel\"></select>\n      </div>\n\n      <button class=\"iconbtn\" id=\"personaToggle\" title=\"\ud83d\ude08=\u4f7f\u7528Worker\u5185\u7f6e\u4eba\u7269\u626e\u6f14 | \ud83d\ude07=\u4e0d\u4f7f\u7528\u5185\u7f6e\uff08\u7f51\u9875\u81ea\u5b9a\u4e49\u624d\u751f\u6548\uff09\">\ud83d\ude08</button>\n      <button class=\"iconbtn\" id=\"settingsBtn\" title=\"Settings\">\u2699\ufe0f</button>\n    </div>\n  </div>\n\n  <div id=\"history\">\n    <div class=\"chat\" id=\"chat\">\n      <div id=\"bottom-spacer\"></div>\n    </div>\n  </div>\n\n  <div class=\"input-floating\">\n    <div class=\"input-inner\" id=\"composer\">\n      <textarea id=\"msg\" rows=\"1\" placeholder=\"Message...\"></textarea>\n      <button id=\"sendBtn\">Send</button>\n    </div>\n  </div>\n\n  <!-- Settings -->\n  <div id=\"settingsMask\">\n    <div id=\"settings\">\n      <div id=\"settingsHeader\">\n        <h3>Settings</h3>\n        <div class=\"hint\">\u6240\u6709\u6570\u636e\u4ec5\u4fdd\u5b58\u5728\u672c\u5730\u6d4f\u89c8\u5668\uff08localStorage\uff09\uff0c\u4e0d\u4f1a\u4e0a\u4f20</div>\n      </div>\n\n      <div class=\"card\">\n        <h4>\u672c\u5730\u5bf9\u8bdd\u8bb0\u5fc6\uff08Local History\uff09</h4>\n        <p>\u5f00\u542f\u540e\uff1a\u5237\u65b0\u9875\u9762/\u91cd\u5f00\u6d4f\u89c8\u5668\u4ecd\u4f1a\u6062\u590d\u5bf9\u8bdd\u3002\u5173\u95ed\u540e\uff1a\u4ec5\u672c\u6b21\u9875\u9762\u4f1a\u8bdd\u6709\u6548\uff0c\u4e0d\u518d\u843d\u76d8\u4fdd\u5b58\u3002<br>\n        \u26a0\ufe0f \u6e05\u9664\u5386\u53f2\u53ea\u4f1a\u5220\u9664\u672c\u5730\u5bf9\u8bdd\uff0c\u4e0d\u4f1a\u5f71\u54cd\u201c\u7f51\u9875\u81ea\u5b9a\u4e49\u4eba\u7269\u6a21\u677f\u201d\u3002</p>\n\n        <div class=\"rowline\">\n          <div class=\"toggle\">\n            <input type=\"checkbox\" id=\"historyKeep\">\n            <label for=\"historyKeep\">\u4fdd\u7559\u672c\u5730\u5386\u53f2\uff08\u542f\u7528\u672c\u5730\u8bb0\u5fc6\uff09</label>\n          </div>\n          <div class=\"btns\">\n            <button class=\"smallbtn danger\" id=\"clearHistory\">\u6e05\u9664\u672c\u5730\u5386\u53f2</button>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"card\">\n        <h4>\u7f51\u9875\u81ea\u5b9a\u4e49\u4eba\u7269\u6a21\u677f\uff08Web Custom Persona\uff09</h4>\n        <p>\u26a0\ufe0f \u4ec5\u5f53\u53f3\u4e0a\u89d2\u4e3a <b>\ud83d\ude07</b>\uff08\u4e0d\u4f7f\u7528 Worker \u5185\u7f6e\u6a21\u677f\uff09\u65f6\uff0c\u6b64\u5904\u624d\u4f1a\u751f\u6548\uff1b<b>\ud83d\ude08 \u4f1a\u5ffd\u7565\u8fd9\u91cc</b>\u3002<br>\n        \u6e05\u9664\u6a21\u677f\u53ea\u4f1a\u5220\u9664\u7f51\u9875\u81ea\u5b9a\u4e49\u5185\u5bb9\uff0c\u4e0d\u4f1a\u5f71\u54cd\u672c\u5730\u5386\u53f2\u3002</p>\n\n        <div class=\"rowline\">\n          <div class=\"toggle\">\n            <input type=\"checkbox\" id=\"promptKeep\">\n            <label for=\"promptKeep\">\u4fdd\u7559\u81ea\u5b9a\u4e49\u4eba\u7269\u6a21\u677f\uff08\u4fdd\u5b58\u5230\u672c\u5730\uff09</label>\n          </div>\n          <div class=\"btns\">\n            <button class=\"smallbtn danger\" id=\"clearPrompt\">\u6e05\u9664\u81ea\u5b9a\u4e49\u6a21\u677f</button>\n          </div>\n        </div>\n\n        <textarea id=\"customPrompt\" placeholder=\"\u4ec5\ud83d\ude07\u65f6\u751f\u6548\uff1a\u5728\u8fd9\u91cc\u5199\u7f51\u9875\u7aef\u81ea\u5b9a\u4e49 system prompt\uff08\u53ef\u591a\u884c\uff09\u3002\"></textarea>\n\n        <div class=\"rowline\">\n          <div></div>\n          <div class=\"btns\">\n            <button class=\"smallbtn\" id=\"savePrompt\">\u4fdd\u5b58</button>\n            <button class=\"smallbtn\" id=\"closeSettings\">\u5173\u95ed</button>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n\n  <!-- Donate -->\n  <div id=\"donateMask\">\n    <div id=\"donateCard\">\n      <div id=\"donateHead\">\n        <div class=\"t\">\u6253\u8d4f / Donate</div>\n        <button id=\"donateClose\">\u2715</button>\n      </div>\n      <div id=\"donateBody\">\n        <img id=\"donateImg\" src=\"/donate.png\" alt=\"WeChat Pay QR\" />\n        <div id=\"donateNote\">\u5982\u679c\u771f\u7684\u5e2e\u52a9\u5230\u4e86\u4f60\uff0c\u8bf7\u4e3a\u4f5c\u8005\u6253\u8d4f\u4e00\u676f\u5496\u5561\u5427\uff0c\u6709\u4e86\u4f60\u7684\u8d5e\u52a9\uff0c\u6211\u4f1a\u5c06\u670d\u52a1\u4e00\u76f4\u8fd0\u884c\u4e0b\u53bb\u7684</div>\n      </div>\n    </div>\n  </div>\n</div>\n\n<script src=\"/config.js\"></script>\n<script src=\"/app.js\"></script>\n</body>\n</html>\n";
const APP_JS = "// public/app.js\n(() => {\n  const historyWrap = document.getElementById(\"history\");\n  const chatEl = document.getElementById(\"chat\");\n  const inputEl = document.getElementById(\"msg\");\n  const composerEl = document.getElementById(\"composer\");\n  const spacerEl = document.getElementById(\"bottom-spacer\");\n\n  const modelSel = document.getElementById(\"modelSel\");\n  const personaToggle = document.getElementById(\"personaToggle\");\n  const settingsBtn = document.getElementById(\"settingsBtn\");\n  const sendBtn = document.getElementById(\"sendBtn\");\n\n  const settingsMask = document.getElementById(\"settingsMask\");\n  const customPromptEl = document.getElementById(\"customPrompt\");\n  const savePromptBtn = document.getElementById(\"savePrompt\");\n  const clearPromptBtn = document.getElementById(\"clearPrompt\");\n  const closeSettingsBtn = document.getElementById(\"closeSettings\");\n  const historyKeepEl = document.getElementById(\"historyKeep\");\n  const clearHistoryBtn = document.getElementById(\"clearHistory\");\n  const promptKeepEl = document.getElementById(\"promptKeep\");\n\n  const donateBtn = document.getElementById(\"donateBtn\");\n  const donateMask = document.getElementById(\"donateMask\");\n  const donateClose = document.getElementById(\"donateClose\");\n\n  const MODELS = (window.APP_MODELS || [\n    { id: \"deepseek-ai/deepseek-v3.2\", label: \"deepseek-v3.2\" },\n    { id: \"z-ai/glm5\", label: \"glm5\" },\n    { id: \"openai/gpt-oss-120b\", label: \"gpt-oss-120b\" },\n  ]);\n\n  const session = [];\n\n  let totalPromptTokens = 0;\n  let totalCompletionTokens = 0;\n  let totalInEstimate = 0;\n  let totalOutEstimate = 0;\n\n  // ====== \u672c\u5730\u5b58\u50a8 Key\uff08\u4e25\u683c\u5206\u79bb\uff1a\u5386\u53f2 vs \u81ea\u5b9a\u4e49\u6a21\u677f\uff09 ======\n  const LS_MODEL = \"cfw_model\";\n  const LS_USE_BUILTIN = \"cfw_use_builtin\";      // \"1\"=\ud83d\ude08, \"0\"=\ud83d\ude07\n\n  const LS_HISTORY_ENABLED = \"cfw_history_enabled\";\n  const LS_CHAT_SESSION = \"cfw_chat_session_v1\";\n\n  const LS_PROMPT_ENABLED = \"cfw_prompt_enabled\";\n  const LS_CUSTOM_PROMPT = \"cfw_custom_prompt_v1\";\n\n  // \u2705 \u9875\u9762\u5bc6\u7801\uff1a\u6bcf\u6b21\u8fdb\u9875\u9762\u90fd\u5f39\u7a97\uff08\u4e0d\u843d\u76d8\uff09\n  let chatPassword = null;\n\n  let useBuiltin = (localStorage.getItem(LS_USE_BUILTIN) ?? \"1\") === \"1\";\n  personaToggle.textContent = useBuiltin ? \"\ud83d\ude08\" : \"\ud83d\ude07\";\n\n  let historyEnabled = (localStorage.getItem(LS_HISTORY_ENABLED) ?? \"0\") === \"1\";\n  let promptEnabled  = (localStorage.getItem(LS_PROMPT_ENABLED) ?? \"1\") === \"1\";\n  historyKeepEl.checked = historyEnabled;\n  promptKeepEl.checked = promptEnabled;\n\n  function estimateTokens(text){\n    if (!text) return 0;\n    let cjk = 0, ascii = 0;\n    for (const ch of text) {\n      const code = ch.charCodeAt(0);\n      if (ch === \" \" || ch === \"\\n\" || ch === \"\\t\" || ch === \"\\r\") continue;\n      const isCJK =\n        (code >= 0x4E00 && code <= 0x9FFF) ||\n        (code >= 0x3400 && code <= 0x4DBF) ||\n        (code >= 0x3040 && code <= 0x30FF) ||\n        (code >= 0xAC00 && code <= 0xD7AF) ||\n        (code >= 0xFF00 && code <= 0xFFEF);\n      if (isCJK) cjk++; else ascii++;\n    }\n    return cjk + Math.ceil(ascii / 4);\n  }\n\n  function updateSpacer(){\n    if (!composerEl || !spacerEl) return;\n    const rect = composerEl.getBoundingClientRect();\n    const rootStyle = getComputedStyle(document.documentElement);\n    const gap = parseFloat(rootStyle.getPropertyValue(\"--composer-gap\")) || 18;\n    const extra = parseFloat(rootStyle.getPropertyValue(\"--spacer-extra\")) || 28;\n    const h = Math.ceil(rect.height + gap + extra);\n    spacerEl.style.height = h + \"px\";\n    historyWrap.style.scrollPaddingBottom = h + \"px\";\n  }\n\n  function isNearBottom(){\n    const threshold = 120;\n    return (historyWrap.scrollHeight - historyWrap.scrollTop - historyWrap.clientHeight) < threshold;\n  }\n  function scrollToBottom(){\n    historyWrap.scrollTo({ top: historyWrap.scrollHeight, behavior: \"auto\" });\n  }\n\n  function makeRow(role){\n    const row = document.createElement(\"div\");\n    row.className = \"row \" + (role === \"user\" ? \"user\" : \"ai\");\n\n    const avatar = document.createElement(\"div\");\n    avatar.className = \"avatar \" + (role === \"user\" ? \"human\" : \"bot\");\n    avatar.textContent = (role === \"user\" ? \"U\" : \"B\");\n\n    const content = document.createElement(\"div\");\n    content.className = \"content\";\n\n    const meta = document.createElement(\"div\");\n    meta.className = \"meta\";\n    meta.textContent = (role === \"user\" ? \"User\" : \"Bot\");\n\n    const bubble = document.createElement(\"div\");\n    bubble.className = \"bubble \" + (role === \"user\" ? \"user\" : \"ai\");\n\n    const stats = document.createElement(\"div\");\n    stats.className = \"stats\";\n\n    content.appendChild(meta);\n    content.appendChild(bubble);\n    content.appendChild(stats);\n\n    if (role === \"user\") {\n      row.appendChild(content);\n      row.appendChild(avatar);\n    } else {\n      row.appendChild(avatar);\n      row.appendChild(content);\n    }\n\n    chatEl.insertBefore(row, spacerEl);\n    if (isNearBottom()) scrollToBottom();\n\n    return { bubble, stats };\n  }\n\n  function clearUIRows(){\n    const nodes = Array.from(chatEl.children);\n    for (const n of nodes) {\n      if (n === spacerEl) continue;\n      chatEl.removeChild(n);\n    }\n  }\n\n  function persistSessionIfEnabled(){\n    if (!historyEnabled) return;\n    try { localStorage.setItem(LS_CHAT_SESSION, JSON.stringify(session)); } catch {}\n  }\n\n  function restoreSessionIfEnabled(){\n    if (!historyEnabled) return;\n    const raw = localStorage.getItem(LS_CHAT_SESSION);\n    if (!raw) return;\n\n    try {\n      const arr = JSON.parse(raw);\n      if (!Array.isArray(arr)) return;\n\n      session.length = 0;\n      for (const m of arr) {\n        if (!m || (m.role !== \"user\" && m.role !== \"assistant\") || typeof m.content !== \"string\") continue;\n        session.push({ role: m.role, content: m.content });\n      }\n\n      clearUIRows();\n      for (const m of session) {\n        const r = makeRow(m.role === \"user\" ? \"user\" : \"assistant\");\n        r.bubble.textContent = m.content;\n        r.stats.textContent = \"\";\n      }\n    } catch {}\n  }\n\n  function initModels(){\n    modelSel.innerHTML = \"\";\n    for (const m of MODELS) {\n      const opt = document.createElement(\"option\");\n      opt.value = m.id;\n      opt.textContent = m.label;\n      modelSel.appendChild(opt);\n    }\n\n    const saved = localStorage.getItem(LS_MODEL);\n    modelSel.value = saved || MODELS[0].id;\n\n    modelSel.addEventListener(\"change\", () => {\n      localStorage.setItem(LS_MODEL, modelSel.value);\n    });\n  }\n\n  // \ud83d\ude08/\ud83d\ude07\n  personaToggle.addEventListener(\"click\", () => {\n    useBuiltin = !useBuiltin;\n    personaToggle.textContent = useBuiltin ? \"\ud83d\ude08\" : \"\ud83d\ude07\";\n    localStorage.setItem(LS_USE_BUILTIN, useBuiltin ? \"1\" : \"0\");\n  });\n\n  // Settings\n  settingsBtn.addEventListener(\"click\", () => {\n    settingsMask.style.display = \"flex\";\n    historyKeepEl.checked = historyEnabled;\n    promptKeepEl.checked = promptEnabled;\n    customPromptEl.value = (localStorage.getItem(LS_CUSTOM_PROMPT) || \"\");\n  });\n  closeSettingsBtn.addEventListener(\"click\", () => {\n    settingsMask.style.display = \"none\";\n  });\n  settingsMask.addEventListener(\"click\", (e) => {\n    if (e.target === settingsMask) settingsMask.style.display = \"none\";\n  });\n\n  // history\n  historyKeepEl.addEventListener(\"change\", () => {\n    historyEnabled = !!historyKeepEl.checked;\n    localStorage.setItem(LS_HISTORY_ENABLED, historyEnabled ? \"1\" : \"0\");\n    if (historyEnabled) persistSessionIfEnabled();\n  });\n  clearHistoryBtn.addEventListener(\"click\", () => {\n    const ok = confirm(\"\u786e\u5b9a\u6e05\u9664\u672c\u5730\u5386\u53f2\uff1f\\n\u53ea\u4f1a\u5220\u9664\u5bf9\u8bdd\u8bb0\u5f55\uff0c\u4e0d\u4f1a\u5f71\u54cd\u7f51\u9875\u81ea\u5b9a\u4e49\u4eba\u7269\u6a21\u677f\u3002\");\n    if (!ok) return;\n    localStorage.removeItem(LS_CHAT_SESSION);\n    session.length = 0;\n    clearUIRows();\n    updateSpacer();\n    scrollToBottom();\n  });\n\n  // custom prompt\n  promptKeepEl.addEventListener(\"change\", () => {\n    promptEnabled = !!promptKeepEl.checked;\n    localStorage.setItem(LS_PROMPT_ENABLED, promptEnabled ? \"1\" : \"0\");\n    if (!promptEnabled) localStorage.removeItem(LS_CUSTOM_PROMPT);\n  });\n  savePromptBtn.addEventListener(\"click\", () => {\n    const val = customPromptEl.value || \"\";\n    if (promptEnabled) localStorage.setItem(LS_CUSTOM_PROMPT, val);\n    else localStorage.removeItem(LS_CUSTOM_PROMPT);\n    settingsMask.style.display = \"none\";\n  });\n  clearPromptBtn.addEventListener(\"click\", () => {\n    const ok = confirm(\"\u786e\u5b9a\u6e05\u9664\u7f51\u9875\u81ea\u5b9a\u4e49\u4eba\u7269\u6a21\u677f\uff1f\\n\u53ea\u4f1a\u5220\u9664\u81ea\u5b9a\u4e49\u6a21\u677f\uff0c\u4e0d\u4f1a\u5f71\u54cd\u672c\u5730\u5386\u53f2\u3002\");\n    if (!ok) return;\n    localStorage.removeItem(LS_CUSTOM_PROMPT);\n    customPromptEl.value = \"\";\n  });\n\n  // donate\n  function openDonate(){ donateMask.style.display = \"flex\"; }\n  function closeDonate(){ donateMask.style.display = \"none\"; }\n  donateBtn.addEventListener(\"click\", openDonate);\n  donateClose.addEventListener(\"click\", closeDonate);\n  donateMask.addEventListener(\"click\", (e) => { if (e.target === donateMask) closeDonate(); });\n\n  // composer\n  inputEl.addEventListener(\"input\", () => {\n    inputEl.style.height = \"auto\";\n    inputEl.style.height = inputEl.scrollHeight + \"px\";\n    const stick = isNearBottom();\n    updateSpacer();\n    if (stick) scrollToBottom();\n  });\n\n  function setupResizeObserver(){\n    if (!composerEl || typeof ResizeObserver === \"undefined\") return;\n    const ro = new ResizeObserver(() => {\n      const stick = isNearBottom();\n      updateSpacer();\n      if (stick) scrollToBottom();\n    });\n    ro.observe(composerEl);\n  }\n  function setupViewportListener(){\n    if (!window.visualViewport) return;\n    window.visualViewport.addEventListener(\"resize\", () => {\n      const stick = isNearBottom();\n      updateSpacer();\n      if (stick) scrollToBottom();\n    });\n  }\n  window.addEventListener(\"resize\", () => {\n    const stick = isNearBottom();\n    updateSpacer();\n    if (stick) scrollToBottom();\n  });\n\n  // \u2705 \u8fdb\u9875\u9762\u5f39\u7a97\u8981\u5bc6\u7801\uff08\u4f60\u8981\u7684\u201c\u6700\u5b8c\u7f8e\u7248\u672c\u201d\u884c\u4e3a\uff09\n  function askPasswordForever(){\n    while (!chatPassword) {\n      const input = prompt(\"\u8bf7\u8f93\u5165\u804a\u5929\u5bc6\u7801:\");\n      if (input === null) continue;\n      chatPassword = input.trim();\n      if (!chatPassword) chatPassword = null;\n    }\n  }\n\n  async function send(){\n    updateSpacer();\n    const text = inputEl.value.trim();\n    if (!text) return;\n\n    const userRow = makeRow(\"user\");\n    userRow.bubble.textContent = text;\n\n    const inEst = estimateTokens(text);\n    totalInEstimate += inEst;\n    userRow.stats.textContent = `Input(\u4f30\u7b97): \u2248${inEst} | Total In(\u4f30\u7b97): \u2248${totalInEstimate}`;\n\n    session.push({ role: \"user\", content: text });\n    persistSessionIfEnabled();\n\n    inputEl.value = \"\";\n    inputEl.style.height = \"auto\";\n    updateSpacer();\n    scrollToBottom();\n\n    const aiRow = makeRow(\"assistant\");\n    let outStartMs = 0;\n    let outEndMs = 0;\n    let full = \"\";\n    let exactUsage = null;\n\n    let customPrompt = \"\";\n    if (!useBuiltin) {\n      if (promptEnabled) customPrompt = localStorage.getItem(LS_CUSTOM_PROMPT) || \"\";\n    }\n\n    const res = await fetch(\"/api/chat\", {\n      method: \"POST\",\n      headers: { \"Content-Type\": \"application/json\" },\n      body: JSON.stringify({\n        password: chatPassword,\n        model: modelSel.value,\n        use_builtin_persona: useBuiltin,\n        custom_system_prompt: customPrompt,\n        messages: session\n      })\n    });\n\n    if (res.status === 403) {\n      alert(\"\u5bc6\u7801\u9519\u8bef\");\n      // \u91cd\u65b0\u8f93\u5165\u5bc6\u7801\uff08\u6309\u4f60\u6700\u5b8c\u7f8e\u7248\u672c\u7684\u4e60\u60ef\uff09\n      chatPassword = null;\n      askPasswordForever();\n      return;\n    }\n\n    if (!res.ok) {\n      const t = await res.text().catch(() => \"\");\n      aiRow.bubble.textContent = `Request failed (${res.status}):\\n${t}`;\n      aiRow.stats.textContent = \"\";\n      return;\n    }\n\n    const reader = res.body.getReader();\n    const decoder = new TextDecoder();\n\n    while (true) {\n      const { done, value } = await reader.read();\n      if (done) break;\n\n      const chunk = decoder.decode(value, { stream: true });\n      const lines = chunk.split(\"\\n\");\n\n      for (const line of lines) {\n        if (!line.startsWith(\"data: \")) continue;\n\n        const jsonStr = line.replace(\"data: \", \"\").trim();\n        if (!jsonStr || jsonStr === \"[DONE]\") continue;\n\n        try {\n          const parsed = JSON.parse(jsonStr);\n          if (parsed.usage) exactUsage = parsed.usage;\n\n          const delta = parsed.choices?.[0]?.delta?.content;\n          if (delta) {\n            if (!outStartMs) outStartMs = performance.now();\n            full += delta;\n            aiRow.bubble.textContent = full;\n            if (isNearBottom()) scrollToBottom();\n          }\n        } catch {}\n      }\n    }\n\n    outEndMs = performance.now();\n    session.push({ role: \"assistant\", content: full });\n    persistSessionIfEnabled();\n\n    const seconds = Math.max(0.001, (outEndMs - (outStartMs || outEndMs)) / 1000);\n\n    if (exactUsage && typeof exactUsage.completion_tokens === \"number\") {\n      const p = exactUsage.prompt_tokens || 0;\n      const c = exactUsage.completion_tokens || 0;\n      const t = exactUsage.total_tokens || (p + c);\n\n      totalPromptTokens += p;\n      totalCompletionTokens += c;\n\n      const tps = c / seconds;\n\n      aiRow.stats.textContent =\n        `Prompt: ${p} | Completion: ${c} | Total: ${t} | Speed: ${tps.toFixed(2)} tok/s | CumPrompt: ${totalPromptTokens} | CumCompletion: ${totalCompletionTokens}`;\n    } else {\n      const outEst = estimateTokens(full);\n      totalOutEstimate += outEst;\n      const tps = outEst / seconds;\n\n      aiRow.stats.textContent =\n        `Output(\u4f30\u7b97): \u2248${outEst} | Total Out(\u4f30\u7b97): \u2248${totalOutEstimate} | Speed(\u4f30\u7b97): ${tps.toFixed(2)} tok/s | (usage\u672a\u8fd4\u56de)`;\n    }\n\n    updateSpacer();\n    scrollToBottom();\n  }\n\n  sendBtn.addEventListener(\"click\", send);\n  inputEl.addEventListener(\"keydown\", (e) => {\n    if (e.key === \"Enter\" && !e.shiftKey) {\n      e.preventDefault();\n      send();\n    }\n  });\n\n  function init(){\n    // \u8fdb\u9875\u9762\u5148\u8981\u5bc6\u7801\n    askPasswordForever();\n\n    initModels();\n    setupResizeObserver();\n    setupViewportListener();\n    updateSpacer();\n    restoreSessionIfEnabled();\n    scrollToBottom();\n  }\n\n  init();\n})();\n";
const STYLES_CSS = "*{ box-sizing:border-box; }\n:root{\n  --bg:#0b0b0b;\n  --border:#222;\n  --muted:#9a9a9a;\n\n  --bubble-ai:#141414;\n  --bubble-user:#1f1f1f;\n\n  --input-bg:#2d2d2d;\n  --input-border:#444;\n\n  --btn-bg:#3b3b3b;\n  --btn-bg-hover:#4a4a4a;\n\n  --composer-gap:18px;\n  --spacer-extra:28px;\n}\nhtml,body{\n  height:100%;\n  margin:0;\n  background:var(--bg);\n  color:#eaeaea;\n  font-family:-apple-system,BlinkMacSystemFont,\"Segoe UI\",Roboto;\n}\n#app{ height:100%; display:flex; flex-direction:column; }\n\n#topbar{\n  position:sticky;\n  top:0;\n  z-index:5;\n  display:flex;\n  justify-content:center;\n  padding:10px 0;\n  background:linear-gradient(to bottom, rgba(11,11,11,.92), rgba(11,11,11,.65));\n  backdrop-filter: blur(8px);\n  border-bottom:1px solid #151515;\n}\n.topbar-inner{\n  width:100%;\n  max-width:760px;\n  padding:0 14px;\n  display:flex;\n  align-items:center;\n  justify-content:flex-end;\n  gap:10px;\n}\n.pill{\n  display:flex;\n  align-items:center;\n  gap:8px;\n  padding:8px 10px;\n  border-radius:999px;\n  border:1px solid #2a2a2a;\n  background:#101010;\n}\n.pill label{ font-size:13px; color:#cfcfcf; }\n\nselect{\n  background:#0f0f0f;\n  color:#fff;\n  border:1px solid #333;\n  border-radius:10px;\n  padding:6px 10px;\n  outline:none;\n}\nselect option{ background:#0f0f0f; color:#fff; }\n\n.iconbtn{\n  width:38px;height:38px;\n  border-radius:999px;\n  border:1px solid #2a2a2a;\n  background:#101010;\n  color:#fff;\n  cursor:pointer;\n  display:flex;\n  align-items:center;\n  justify-content:center;\n  font-size:18px;\n  transition:.15s;\n}\n.iconbtn:hover{ background:#161616; }\n\n#history{\n  flex:1;\n  overflow-y:auto;\n  -webkit-overflow-scrolling:touch;\n  display:flex;\n  justify-content:center;\n  padding:18px 0 18px 0;\n}\n.chat{\n  width:100%;\n  max-width:760px;\n  padding:0 16px;\n}\n.row{\n  display:flex;\n  gap:10px;\n  margin:12px 0;\n  align-items:flex-start;\n}\n.row.ai{ justify-content:flex-start; }\n.row.user{ justify-content:flex-end; }\n\n.avatar{\n  width:34px;height:34px;\n  border-radius:999px;\n  display:inline-flex;\n  align-items:center;\n  justify-content:center;\n  flex:0 0 34px;\n  font-weight:700;\n  font-size:13px;\n  user-select:none;\n  border:1px solid var(--border);\n}\n.avatar.bot{ background:radial-gradient(circle at 30% 30%, #3a3a3a, #161616); }\n.avatar.human{ background:radial-gradient(circle at 30% 30%, #404040, #1b1b1b); }\n\n.content{\n  display:flex;\n  flex-direction:column;\n  gap:6px;\n  max-width:min(640px,78vw);\n}\n.meta{\n  font-size:12px;\n  color:var(--muted);\n  padding:0 4px;\n}\n.bubble{\n  padding:12px 14px;\n  border-radius:16px;\n  line-height:1.6;\n  white-space:pre-wrap;\n  word-break:break-word;\n  border:1px solid var(--border);\n}\n.bubble.ai{ background:var(--bubble-ai); }\n.bubble.user{ background:var(--bubble-user); }\n\n.row.user .content{ align-items:flex-end; }\n.row.user .meta{ text-align:right; }\n\n.stats{\n  font-size:12px;\n  color:#7f7f7f;\n  padding:0 4px;\n  line-height:1.3;\n}\n\n#bottom-spacer{ width:100%; height:180px; }\n\n.input-floating{\n  position:fixed;\n  bottom:var(--composer-gap);\n  left:0;\n  width:100%;\n  display:flex;\n  justify-content:center;\n  pointer-events:none;\n}\n.input-inner{\n  pointer-events:auto;\n  width:100%;\n  max-width:760px;\n  margin:0 14px;\n  background:var(--input-bg);\n  border:1px solid var(--input-border);\n  border-radius:26px;\n  padding:10px 12px;\n  display:flex;\n  align-items:flex-end;\n  gap:10px;\n  box-shadow:0 10px 30px rgba(0,0,0,.45);\n}\ntextarea#msg{\n  flex:1;\n  resize:none;\n  border:none;\n  outline:none;\n  background:transparent;\n  color:#fff;\n  font-size:15px;\n  max-height:200px;\n  padding:6px 6px 6px 10px;\n}\nbutton#sendBtn{\n  border:none;\n  color:#fff;\n  background:var(--btn-bg);\n  padding:9px 14px;\n  border-radius:18px;\n  cursor:pointer;\n  transition:.15s;\n  flex:0 0 auto;\n}\nbutton#sendBtn:hover{ background:var(--btn-bg-hover); }\n\n/* Settings */\n#settingsMask{\n  position:fixed;\n  inset:0;\n  background:rgba(0,0,0,.55);\n  display:none;\n  align-items:center;\n  justify-content:center;\n  z-index:10;\n  padding:16px;\n}\n#settings{\n  width:min(760px,92vw);\n  border:1px solid #2a2a2a;\n  background:#0f0f0f;\n  border-radius:18px;\n  box-shadow:0 30px 80px rgba(0,0,0,.6);\n  padding:14px;\n}\n#settingsHeader{\n  display:flex;\n  align-items:center;\n  justify-content:space-between;\n  gap:12px;\n  margin-bottom:10px;\n}\n#settingsHeader h3{ margin:0; font-size:16px; color:#eaeaea; }\n#settingsHeader .hint{ font-size:12px; color:#9f9f9f; }\n\n.card{\n  border:1px solid #242424;\n  background:#101010;\n  border-radius:14px;\n  padding:12px;\n  margin:10px 0;\n}\n.card h4{ margin:0 0 8px 0; font-size:14px; color:#eaeaea; }\n.card p{ margin:0 0 10px 0; font-size:12px; color:#9c9c9c; line-height:1.5; }\n\n.rowline{\n  display:flex;\n  align-items:center;\n  justify-content:space-between;\n  gap:10px;\n  padding:8px 0;\n  border-top:1px solid #1c1c1c;\n}\n.rowline:first-of-type{ border-top:none; }\n\n.toggle{ display:flex; align-items:center; gap:10px; user-select:none; }\n.toggle input{ transform: scale(1.1); }\n\n.btns{ display:flex; gap:10px; flex-wrap:wrap; }\n\n.smallbtn{\n  border:1px solid #2a2a2a;\n  background:#141414;\n  color:#fff;\n  border-radius:12px;\n  padding:8px 12px;\n  cursor:pointer;\n}\n.smallbtn:hover{ background:#1b1b1b; }\n.smallbtn.danger{ border-color:#3a1f1f; background:#1a0f0f; }\n.smallbtn.danger:hover{ background:#241010; }\n\n#customPrompt{\n  width:100%;\n  min-height:160px;\n  resize:vertical;\n  border-radius:12px;\n  background:#0f0f0f;\n  border:1px solid #2f2f2f;\n  color:#fff;\n  padding:10px;\n  outline:none;\n  font-size:13px;\n  line-height:1.5;\n}\n\n/* Donate modal */\n#donateMask{\n  position:fixed;\n  inset:0;\n  background:rgba(0,0,0,0.65);\n  display:none;\n  align-items:center;\n  justify-content:center;\n  z-index:30;\n  padding:16px;\n}\n#donateCard{\n  width:min(520px, 92vw);\n  border-radius:18px;\n  border:1px solid rgba(255,255,255,0.10);\n  background:rgba(16,16,16,0.92);\n  box-shadow:0 30px 90px rgba(0,0,0,0.65);\n  overflow:hidden;\n}\n#donateHead{\n  display:flex;\n  align-items:center;\n  justify-content:space-between;\n  padding:12px 14px;\n  border-bottom:1px solid rgba(255,255,255,0.08);\n}\n#donateHead .t{ font-weight:700; }\n#donateClose{\n  width:34px;height:34px;\n  border-radius:999px;\n  border:1px solid rgba(255,255,255,0.10);\n  background:rgba(30,30,30,0.55);\n  color:#fff;\n  cursor:pointer;\n}\n#donateBody{\n  padding:14px;\n  display:flex;\n  flex-direction:column;\n  gap:10px;\n}\n#donateImg{\n  width:100%;\n  border-radius:14px;\n  border:1px solid rgba(255,255,255,0.08);\n  display:block;\n}\n#donateNote{\n  font-size:12px;\n  color:#bdbdbd;\n  line-height:1.5;\n}\n\n@media (max-width:768px){\n  .chat{ padding:0 12px; }\n  .avatar{ width:30px;height:30px;flex-basis:30px;font-size:12px; }\n  .content{ max-width:86vw; }\n  textarea#msg{ font-size:16px; }\n  .input-inner{ margin:0 10px;border-radius:20px; }\n  button#sendBtn{ padding:9px 12px;border-radius:16px; }\n  :root{ --composer-gap:12px; }\n  .topbar-inner{ padding:0 10px; }\n}\n\n::-webkit-scrollbar{ width:6px; }\n::-webkit-scrollbar-thumb{ background:#2a2a2a;border-radius:4px; }\n";
const CLIENT_CONFIG_JS = "// public/config.js\n// \u4ec5\u7528\u4e8e\u524d\u7aef UI\uff08\u6a21\u578b\u4e0b\u62c9\u7684\u663e\u793a\uff09\uff0c\u4e0d\u5305\u542b\u4efb\u4f55\u654f\u611f\u4fe1\u606f\nwindow.APP_MODELS = [\n  { id: \"deepseek-ai/deepseek-v3.2\", label: \"deepseek-v3.2\" },\n  { id: \"z-ai/glm5\", label: \"glm5\" },\n  { id: \"openai/gpt-oss-120b\", label: \"gpt-oss-120b\" },\n];\n";

function resp(body, ct, status=200) {
  return new Response(body, { status, headers: { "Content-Type": ct } });
}

function isAllowedModel(id) {
  return MODELS.some(m => m.id === id);
}

function builtinPromptForModel(modelId) {
  const meta = MODELS.find(m => m.id === modelId);
  const persona = meta?.persona ?? 1;
  return persona === 2 ? PROMPT_2 : PROMPT_1;
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);

    // Static
    if (request.method === "GET" && url.pathname === "/") {
      return resp(INDEX_HTML, "text/html; charset=utf-8");
    }
    if (request.method === "GET" && url.pathname === "/app.js") {
      return resp(APP_JS, "text/javascript; charset=utf-8");
    }
    if (request.method === "GET" && url.pathname === "/styles.css") {
      return resp(STYLES_CSS, "text/css; charset=utf-8");
    }
    if (request.method === "GET" && url.pathname === "/config.js") {
      return resp(CLIENT_CONFIG_JS, "text/javascript; charset=utf-8");
    }
    if (request.method === "GET" && url.pathname === "/donate.png") {
      const bytes = Uint8Array.from(atob(DONATE_PNG_BASE64), c => c.charCodeAt(0));
      return new Response(bytes, {
        headers: {
          "Content-Type": "image/png",
          "Cache-Control": "public, max-age=31536000, immutable",
        }
      });
    }

    // Chat API
    if (url.pathname === "/api/chat" && request.method === "POST") {
      let payload;
      try {
        payload = await request.json();
      } catch {
        return resp("Bad JSON", "text/plain; charset=utf-8", 400);
      }

      if ((payload?.password ?? "") !== CHAT_PASSWORD) {
        return resp("Invalid password", "text/plain; charset=utf-8", 403);
      }

      const model = isAllowedModel(payload?.model) ? payload.model : DEFAULT_MODEL;
      const useBuiltin = payload?.use_builtin_persona !== false; // default true
      const customSystem = typeof payload?.custom_system_prompt === "string" ? payload.custom_system_prompt : "";
      const messages = Array.isArray(payload?.messages) ? payload.messages : [];

      const upstreamMessages = [];
      if (useBuiltin) {
        upstreamMessages.push({ role: "system", content: builtinPromptForModel(model) });
      } else if (customSystem.trim()) {
        upstreamMessages.push({ role: "system", content: customSystem.trim() });
      }

      for (const m of messages) {
        if (!m || (m.role !== "user" && m.role !== "assistant")) continue;
        upstreamMessages.push({ role: m.role, content: m.content ?? "" });
      }

      if (!env.NVIDIA_API_KEY) {
        return resp("Missing NVIDIA_API_KEY (set with wrangler secret).", "text/plain; charset=utf-8", 500);
      }

      const body = {
        model,
        stream: true,
        stream_options: { include_usage: true },
        messages: upstreamMessages,
      };

      const upstream = await fetch("https://integrate.api.nvidia.com/v1/chat/completions", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${env.NVIDIA_API_KEY}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify(body),
      });

      if (!upstream.ok) {
        const t = await upstream.text().catch(() => "");
        return resp(`Upstream error ${upstream.status}: ${t}`, "text/plain; charset=utf-8", 502);
      }

      return new Response(upstream.body, {
        headers: {
          "Content-Type": "text/event-stream; charset=utf-8",
          "Cache-Control": "no-cache",
          "Connection": "keep-alive",
        },
      });
    }

    return resp("Not found", "text/plain; charset=utf-8", 404);
  }
};
